exercises.expected_solution:
import java.util.*;
import java.util.function.*;
public class App {
    public static void main(String[] args) {
        List<Integer> nums = Arrays.asList(11, 12, 13, 14, 20);

        Predicate<Integer> isEven   = n -> n % 2 == 0;
        Predicate<Integer> greaterThan10 = n -> n > 10;

        // and
        List<Integer> evenAndLarge = new ArrayList<>();
        nums.forEach(n -> { if (isEven.and(greaterThan10).test(n)) evenAndLarge.add(n); });
        System.out.println("Even AND > 10: " + evenAndLarge);

        // or
        List<Integer> evenOrLarge = new ArrayList<>();
        nums.forEach(n -> { if (isEven.or(greaterThan10).test(n)) evenOrLarge.add(n); });
        System.out.println("Even OR > 10: " + evenOrLarge);

        // negate
        List<Integer> notEven = new ArrayList<>();
        nums.forEach(n -> { if (isEven.negate().test(n)) notEven.add(n); });
        System.out.println("Not even: " + notEven);
    }
}

