import java.util.*;
import java.util.function.*;
public class App {
    static int countMatching(List<String> list, Predicate<String> condition) {
        int count = 0;
        for (String s : list) {
            if (condition.test(s)) count++;
        }
        return count;
    }

    public static void main(String[] args) {
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya", "Vikram", "Anita");

        System.out.println("Length > 3: " + countMatching(names, s -> s.length() > 3));
        System.out.println("Starts with A: " + countMatching(names, s -> s.startsWith("A")));
        System.out.println("Contains 'ia': " + countMatching(names, s -> s.contains("ia")));
    }
}

