import java.util.*;
import java.util.function.*;
public class App {
    static <T, R> List<R> transformAll(List<T> list, Function<T, R> mapper) {
        List<R> result = new ArrayList<>();
        for (T item : list) result.add(mapper.apply(item));
        return result;
    }

    public static void main(String[] args) {
        List<String> names = Arrays.asList("Aisha", "Raj", "Priya", "Vikram");

        // String → Integer (length)
        System.out.println(transformAll(names, s -> s.length()));

        // String → String (uppercase)
        System.out.println(transformAll(names, String::toUpperCase));
    }
}

