import java.util.*;
import java.util.function.*;
class Product {
    String name; double price;
    Product(String n, double p) { name = n; price = p; }
}
public class App {
    public static void main(String[] args) {
        List<String> auditLog = new ArrayList<>();

        Consumer<Product> printer = p -> System.out.println("Product: " + p.name + " ₹" + p.price);
        Consumer<Product> logger  = p -> auditLog.add(p.name + " logged");

        Consumer<Product> both = printer.andThen(logger);

        List<Product> products = Arrays.asList(new Product("Mouse", 799), new Product("Keyboard", 1999));
        products.forEach(both);

        System.out.println("Log: " + auditLog);
    }
}

