public class App {
    public static void main(String[] args) {
        Predicate<String> notBlank    = s -> s != null && !s.isBlank();
        Predicate<String> goodLength  = s -> s.length() >= 5 && s.length() <= 20;
        Predicate<String> noSpaces    = s -> !s.contains(" ");
        Predicate<String> startsAlpha = s -> Character.isLetter(s.charAt(0));

