            .and(goodLength)
            .and(noSpaces)
            .and(startsAlpha);

        String[] tests = {"aisha123", " spaces ", "hi", "123start", "validUser2024"};
        for (String name : tests) {
            System.out.println(name + ": " + (validUsername.test(name) ? "VALID" : "INVALID"));
