import java.util.*;
import java.util.function.*;
// ReportPrinter using all four functional interfaces

exercises.expected_solution:
import java.util.*;
import java.util.function.*;
class Employee {
    String name, dept;
    double salary;
    Employee(String n, String d, double s) { name=n; dept=d; salary=s; }
}
class ReportPrinter<T> {
    private Supplier<List<T>> dataSource;
    private Predicate<T> filter;
    private Function<T, String> formatter;
    private Consumer<String> outputter;

    ReportPrinter(Supplier<List<T>> ds, Predicate<T> f, Function<T, String> fmt, Consumer<String> out) {
        dataSource = ds; filter = f; formatter = fmt; outputter = out;
    }

    void print(String title) {
        outputter.accept("=== " + title + " ===");
        List<T> data = dataSource.get();
        int count = 0;
        for (T item : data) {
            if (filter.test(item)) {
                outputter.accept(formatter.apply(item));
                count++;
            }
        }
        outputter.accept("=== " + count + " records ===");
    }
}
public class App {
    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee("Aisha",  "Engineering", 95000),
            new Employee("Raj",    "Sales",        72000),
            new Employee("Priya",  "Engineering",  88000),
            new Employee("Vikram", "Sales",         65000)
        );

        new ReportPrinter<Employee>(
            () -> employees,                                  // Supplier
            e -> e.dept.equals("Engineering"),               // Predicate
            e -> e.name + ": ₹" + e.salary + " (" + e.dept + ")",  // Function
            System.out::println                              // Consumer
        ).print("Employee Report");
    }
}

