import java.util.*;
import java.util.function.*;
// ScoringEngine — all functional interfaces

exercises.expected_solution:
import java.util.*;
import java.util.function.*;
class Player {
    String name; int skill, loyalty;
    Player(String n, int s, int l) { name=n; skill=s; loyalty=l; }
}
class ScoringEngine<T> {
    Function<T, Integer> baseScorer;
    Function<T, Integer> bonusScorer;
    Predicate<T> qualifiesForBonus;
    Supplier<Integer> maxScore;
    BiConsumer<T, Integer> reporter;

    ScoringEngine(Function<T,Integer> base, Function<T,Integer> bonus,
                  Predicate<T> qualifies, Supplier<Integer> max, BiConsumer<T,Integer> rep) {
        this.baseScorer = base; this.bonusScorer = bonus;
        this.qualifiesForBonus = qualifies; this.maxScore = max; this.reporter = rep;
    }

    void score(List<T> items) {
        items.forEach(item -> {
            int base  = baseScorer.apply(item);
            int bonus = qualifiesForBonus.test(item) ? bonusScorer.apply(item) : 0;
            int total = Math.min(base + bonus, maxScore.get());
            reporter.accept(item, total);
        });
    }
}
public class App {
    public static void main(String[] args) {
        List<Player> players = Arrays.asList(
            new Player("Aisha",  92, 5),
            new Player("Raj",    85, 2),
            new Player("Priya",  98, 3),
            new Player("Vikram", 70, 1)
        );

        new ScoringEngine<Player>(
            p -> p.skill,                    // base = skill
            p -> p.loyalty * 2,              // bonus = loyalty * 2
            p -> p.loyalty >= 3,             // qualifies if loyalty >= 3
            () -> 100,                       // max = 100
            (p, score) -> {
                int raw = p.skill + (p.loyalty >= 3 ? p.loyalty * 2 : 0);
                String cap = raw > 100 ? " (capped from " + raw + ")" : "";
                System.out.println(p.name + ": " + score + cap);
            }
        ).score(players);
    }
}
